{"id":"php:src/Illuminate/Foundation/Http/Kernel.php#sendRequestThroughRouter@164","source":"protected function sendRequestThroughRouter($request)
    {
        $this->app->instance('request', $request);

        Request::clearResolvedInstance();

        $this->bootstrap();

        return (new Pipeline($this->app))
            ->send($request)
            ->through($this->app->shouldSkipMiddleware() ? [] : $this->middleware)
            ->then($this->dispatchToRouter());
    }"}

{"id":"php:src/Illuminate/Foundation/Http/Kernel.php#dispatchToRouter@195","source":"protected function dispatchToRouter()
    {
        return function ($request) {
            $this->app->instance('request', $request);

            return $this->router->dispatch($request);
        };
    }"}

